import math

class SparseTable:
    def __init__(self, arr):
        n    = len(arr)
        LOG  = max(1, n.bit_length())
        self.table = [[0]*n for _ in range(LOG)]
        self.log2  = [0] * (n + 1)
        for i in range(2, n + 1):
            self.log2[i] = self.log2[i // 2] + 1

        self.table[0] = arr[:]
        for j in range(1, LOG):
            for i in range(n - (1 << j) + 1):
                self.table[j][i] = min(
                    self.table[j-1][i],
                    self.table[j-1][i + (1 << (j-1))]
                )

    def query(self, l, r):
        """Minimum of arr[l..r] (0-indexed, inclusive) in O(1)."""
